  vayne: { diff: "EVEN", tone: "#e8b84b", tldr: "E-stun to stick \u2014 R-wall her kiting and all-in early.", breakdown: "Vayne kites you. E-stun to stick, R-wall her escape, and all-in early before she scales.", dos: ["E-stun to stick to her", "R-wall her kiting path", "All-in early before she scales"], donts: ["Chase her tumbles", "Get condemned into a wall", "Run out of Q targets"], key: { slot: "E", name: "Condemn", cd: "18s", note: "Wall-stun. Stun her so she can\u2019t kite.", winT: "CONDEMN DOWN", winS: "E-stun + Q her." }, hold: "Hold R (Vanguard\u2019s Edge) to wall off her tumble escape \u2014 trap her against your blades.", tip: "R-wall behind her so her Q-tumble has nowhere to go \u2014 then E-stun + Q-reset to finish her.", win: "E-stun to stick, R-wall her, all-in early." },
  warwick: { diff: "EVEN", tone: "#e8b84b", tldr: "Anti-heal his Q \u2014 W his R lock and E-stun him.", breakdown: "Anti-heal, W-block his R lock-on burst, and E-stun + shred him.", dos: ["Anti-heal his Q sustain", "W-block his R lock", "E-stun + shred him"], donts: ["Extend into his heal", "Get R-suppressed", "Run out of Q targets"], key: { slot: "R", name: "Infinite Duress", cd: "90s", note: "His all-in lock. W or dodge it.", winT: "DURESS DOWN", winS: "E-stun + Q him." }, hold: "Hold W for his R suppress \u2014 the damage reduction blunts his lock-on burst.", tip: "Drop W the instant his R suppress lands \u2014 you take half damage while locked, then E-stun him after.", win: "Anti-heal, W his R, and E-stun him." },
  wukong: { diff: "EVEN", tone: "#e8b84b", tldr: "Don\u2019t E-stun the clone \u2014 stun the real body when his E is down.", breakdown: "Wait out his clone, W his burst, and E-stun the real body when his E is down.", dos: ["Wait for his W decoy", "W-block his combo", "E-stun the real body"], donts: ["E-stun the clone", "Trade into his Q shred", "Run out of Q targets"], key: { slot: "E", name: "Nimbus Strike", cd: "8s", note: "His escape. Stun him when it\u2019s down.", winT: "NIMBUS DOWN", winS: "E-stun + Q him." }, hold: "Hold W for his E-dive + R knockup \u2014 the damage reduction halves the combo.", tip: "Don\u2019t E-stun his clone \u2014 wait for the decoy to fade, then E-stun the real Wukong when his E is down.", win: "Don\u2019t get baited; E-stun the real body." },
